import { getZoomTransformFromAxis } from '../tools/apply-zoom-transform-on-scale';

/**
 * #ZC2260
 * @param behaviour
 */
export function updateChartZoomTransform(behaviour) {
    let eventManager = this,
        chart = eventManager.chart,
        existingScale = behaviour.instance.getTransform(),
        types = behaviour.types || {};

    let x, y;
    if (types.x) {
        x = chart.axes.x;
    }
    if (types.y) {
        y = chart.axes.y.groups[0];
    }

    if (chart.axes.rotated) {
        [x, y] = [y, x];
    }

    let transform = getZoomTransformFromAxis(existingScale.k, x, y, chart);

    // just update the zoom transform in the context
    behaviour.instance.zoomToIdentity(transform, 0, false);
}
